// ============================================================================
// Simple JSON Parser (minimal, handles our protocol only)
// ============================================================================

static const char* json_find_string(const char* json, const char* key, char* out, size_t out_size) {
    char search[64];
    snprintf(search, sizeof(search), "\"%s\"", key);

    const char* pos = strstr(json, search);
    if (!pos) return nullptr;

    pos = strchr(pos + strlen(search), ':');
    if (!pos) return nullptr;

    // Skip whitespace
    while (*pos && (*pos == ':' || *pos == ' ' || *pos == '\t')) pos++;

    if (*pos != '"') return nullptr;
    pos++;  // Skip opening quote

    const char* end = strchr(pos, '"');
    if (!end) return nullptr;

    size_t len = end - pos;
    if (len >= out_size) len = out_size - 1;

    strncpy_s(out, out_size, pos, len);
    out[len] = '\0';

    return pos;
}

static bool json_find_int(const char* json, const char* key, int* out) {
    char search[64];
    snprintf(search, sizeof(search), "\"%s\"", key);

    const char* pos = strstr(json, search);
    if (!pos) return false;

    pos = strchr(pos + strlen(search), ':');
    if (!pos) return false;

    // Skip whitespace
    while (*pos && (*pos == ':' || *pos == ' ' || *pos == '\t')) pos++;

    *out = atoi(pos);
    return true;
}

static bool json_find_bool(const char* json, const char* key, bool* out) {
    char search[64];
    snprintf(search, sizeof(search), "\"%s\"", key);

    const char* pos = strstr(json, search);
    if (!pos) return false;

    pos = strchr(pos + strlen(search), ':');
    if (!pos) return false;

    // Skip whitespace
    while (*pos && (*pos == ':' || *pos == ' ' || *pos == '\t')) pos++;

    *out = (strncmp(pos, "true", 4) == 0);
    return true;
}

static bool json_find_float(const char* json, const char* key, float* out) {
    char search[64];
    snprintf(search, sizeof(search), "\"%s\"", key);

    const char* pos = strstr(json, search);
    if (!pos) return false;

    pos = strchr(pos + strlen(search), ':');
    if (!pos) return false;

    // Skip whitespace
    while (*pos && (*pos == ':' || *pos == ' ' || *pos == '\t')) pos++;

    *out = (float)atof(pos);
    return true;
}

// ============================================================================
// Screenshot Handler (called from main thread via WM_IPC_CAPTURE_SCREENSHOT)
// ============================================================================

void ipc_handle_screenshot_request() {
    EnterCriticalSection(&g_screenshot_cs);

    // Free any previous buffer
    if (g_screenshot_buffer) {
        ipc_free_screenshot_buffer(g_screenshot_buffer);
        g_screenshot_buffer = nullptr;
        g_screenshot_size = 0;
    }

    // Capture screenshot
    ipc_capture_screenshot_to_png(&g_screenshot_buffer, &g_screenshot_size);

    LeaveCriticalSection(&g_screenshot_cs);

    // Signal that screenshot is ready
    SetEvent(g_screenshot_ready_event);
}

// ============================================================================
// Message Handlers
// ============================================================================

static bool handle_screenshot_request(HANDLE pipe) {
    // Request screenshot on main thread
    ResetEvent(g_screenshot_ready_event);
    PostMessageW(g_main_window, WM_IPC_CAPTURE_SCREENSHOT, 0, 0);

    // Wait for screenshot to be captured
    DWORD wait_result = WaitForSingleObject(g_screenshot_ready_event, IPC::SCREENSHOT_TIMEOUT_MS);
    if (wait_result != WAIT_OBJECT_0) {
        // Timeout or error
        const char* error = "{\"type\":\"screenshot\",\"success\":false,\"error\":\"timeout\"}";
        DWORD written;
        WriteFile(pipe, error, (DWORD)strlen(error), &written, nullptr);
        return false;
    }

    EnterCriticalSection(&g_screenshot_cs);

    if (!g_screenshot_buffer || g_screenshot_size == 0) {
        LeaveCriticalSection(&g_screenshot_cs);
        const char* error = "{\"type\":\"screenshot\",\"success\":false,\"error\":\"capture_failed\"}";
        DWORD written;
        WriteFile(pipe, error, (DWORD)strlen(error), &written, nullptr);
        return false;
    }

    // Get window dimensions for response
    RECT rc;
    GetClientRect(g_main_window, &rc);
    int width = rc.right - rc.left;
    int height = rc.bottom - rc.top;

    // Send JSON header
    char header[256];
    snprintf(header, sizeof(header),
        "{\"type\":\"screenshot\",\"success\":true,\"width\":%d,\"height\":%d,\"data_size\":%zu}\n",
        width, height, g_screenshot_size);

    DWORD written;
    WriteFile(pipe, header, (DWORD)strlen(header), &written, nullptr);

    // Send binary PNG data
    WriteFile(pipe, g_screenshot_buffer, (DWORD)g_screenshot_size, &written, nullptr);

    // Free the buffer
    ipc_free_screenshot_buffer(g_screenshot_buffer);
    g_screenshot_buffer = nullptr;
    g_screenshot_size = 0;

    LeaveCriticalSection(&g_screenshot_cs);

    return true;
}

static bool handle_mouse_click(HANDLE pipe, const char* json) {
    int x = 0, y = 0;
    char button_str[16] = "left";

    json_find_int(json, "x", &x);
    json_find_int(json, "y", &y);
    json_find_string(json, "button", button_str, sizeof(button_str));

    int button = 0;
    if (strcmp(button_str, "right") == 0) button = 1;
    else if (strcmp(button_str, "middle") == 0) button = 2;

    // Inject mouse events
    ipc_inject_mouse_move(x, y);
    ipc_inject_mouse_down(x, y, button);
    ipc_inject_mouse_up(x, y, button);

    // Send response (with newline for ReadLine compatibility)
    const char* response = "{\"type\":\"mouse_click\",\"success\":true}\n";
    DWORD written;
    WriteFile(pipe, response, (DWORD)strlen(response), &written, nullptr);

    return true;
}

